/* eslint-disable @typescript-eslint/no-magic-numbers */
import React from 'react';
import MoreOutlined from '@universe-design/icons-react/MoreOutlined';

export function getTextAvatarFontSizeBySize(size: number) {
  if (size >= 32) {
    return 12;
  }
  return 10;
}

export function getAvatarGroupMoreContent({ size, hideCount }: { size: number; hideCount: number }) {
  // 较小尺寸的 avatar 显示到 99+
  if (size < 32) {
    if (hideCount < 100) {
      return `+${hideCount}`;
    }
    return <MoreOutlined />;
  }

  //  较大尺寸的 avatar 可以显示到 999+
  if (hideCount < 1000) {
    return `+${hideCount}`;
  }
  return <MoreOutlined />;
}
